const html = "<!doctype html>\n<html lang=\"es\">\n  <head>\n    <meta charset=\"UTF-8\" />\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\n    <meta name=\"description\" content=\"Sistema web para comercio con ventas, proveedores, stock y facturacion.\" />\n    <link rel=\"icon\" type=\"image/svg+xml\" href=\"/favicon.svg\" />\n    <link rel=\"stylesheet\" href=\"/app.css\" />\n    <title>Comercio 360</title>\n  </head>\n  <body>\n    <div id=\"app\"></div>\n    <script src=\"/app.js\"></script>\n  </body>\n</html>\n";
const css = "@import url('https://fonts.googleapis.com/css2?family=Roboto:wght@400;500;700&display=swap');\n\n:root {\n  --bg: #6f7782;\n  --bg-soft: #ebedf0;\n  --panel: #f6f6f6;\n  --panel-edge: #d3d8dd;\n  --ink: #5e646c;\n  --ink-strong: #49505a;\n  --nav: #303640;\n  --nav-edge: #252a33;\n  --topbar: #3c434e;\n  --accent: #7d848d;\n  --warning: #efe8c4;\n  --success: #dbe8d8;\n  font-family: 'Roboto', sans-serif;\n  color: var(--ink);\n  background: linear-gradient(180deg, #7b838d 0%, #6b737d 100%);\n  font-synthesis: none;\n  text-rendering: optimizeLegibility;\n  -webkit-font-smoothing: antialiased;\n  -moz-osx-font-smoothing: grayscale;\n}\n\n* {\n  box-sizing: border-box;\n}\n\nhtml {\n  scroll-behavior: smooth;\n}\n\nbody {\n  margin: 0;\n  min-width: 320px;\n}\n\nbutton,\ninput,\nselect {\n  font: inherit;\n}\n\nbutton {\n  cursor: pointer;\n}\n\ninput,\nselect {\n  outline: none;\n}\n\n#app {\n  min-height: 100vh;\n}\n\n.app-shell {\n  display: grid;\n  grid-template-columns: 88px 1fr;\n  min-height: 100vh;\n}\n\n.nav-rail {\n  display: flex;\n  flex-direction: column;\n  justify-content: space-between;\n  background: linear-gradient(180deg, var(--nav) 0%, var(--nav-edge) 100%);\n  color: #d7dbe0;\n  padding: 14px 8px;\n  border-right: 1px solid rgba(0, 0, 0, 0.22);\n}\n\n.brand-stack {\n  display: grid;\n  gap: 18px;\n}\n\n.brand-logo {\n  width: 54px;\n  height: 54px;\n  margin: 0 auto;\n  border-radius: 16px;\n  display: grid;\n  place-items: center;\n  background: rgba(255, 255, 255, 0.08);\n  font-size: 1.7rem;\n  font-weight: 700;\n  text-transform: lowercase;\n}\n\n.rail-items {\n  display: grid;\n  gap: 8px;\n}\n\n.rail-items a,\n.rail-foot {\n  display: block;\n  border-radius: 14px;\n  padding: 10px 8px;\n  font-size: 0.76rem;\n  text-align: center;\n  color: inherit;\n  background: rgba(255, 255, 255, 0.04);\n  text-decoration: none;\n}\n\n.rail-foot {\n  color: #aeb6c0;\n}\n\n.workspace {\n  display: grid;\n  grid-template-rows: auto 1fr;\n}\n\n.topbar {\n  display: grid;\n  grid-template-columns: 240px minmax(0, 1fr) 180px;\n  align-items: center;\n  gap: 16px;\n  background: linear-gradient(180deg, #4a515b 0%, var(--topbar) 100%);\n  color: #e8edf1;\n  padding: 14px 20px;\n  box-shadow: inset 0 -1px 0 rgba(255, 255, 255, 0.06);\n}\n\n.topbar-left strong,\n.topbar-left span {\n  display: block;\n}\n\n.topbar-left strong {\n  font-size: 1rem;\n  text-transform: lowercase;\n}\n\n.topbar-left span {\n  margin-top: 3px;\n  font-size: 0.78rem;\n  color: #c7cdd5;\n}\n\n.searchbar {\n  display: flex;\n  align-items: center;\n  gap: 10px;\n  background: rgba(0, 0, 0, 0.18);\n  border: 1px solid rgba(255, 255, 255, 0.08);\n  border-radius: 6px;\n  padding: 8px 12px;\n}\n\n.searchbar input {\n  width: 100%;\n  border: 0;\n  background: transparent;\n  color: #f3f5f7;\n}\n\n.searchbar input::placeholder {\n  color: #bcc4cd;\n}\n\n.topbar-right {\n  display: flex;\n  justify-content: flex-end;\n  align-items: center;\n  gap: 10px;\n}\n\n.status-pill {\n  border: 1px solid rgba(255, 255, 255, 0.16);\n  border-radius: 999px;\n  padding: 5px 10px;\n  font-size: 0.76rem;\n}\n\n.avatar {\n  width: 32px;\n  height: 32px;\n  border-radius: 50%;\n  display: grid;\n  place-items: center;\n  background: rgba(255, 255, 255, 0.14);\n  font-weight: 700;\n}\n\n.page {\n  padding: 22px 24px 32px;\n}\n\n.dashboard-card,\n.metric-box,\n.panel {\n  border: 1px solid var(--panel-edge);\n  background: linear-gradient(180deg, #fdfdfd 0%, var(--panel) 100%);\n  box-shadow: 0 2px 0 rgba(255, 255, 255, 0.65) inset, 0 14px 28px rgba(32, 39, 45, 0.08);\n}\n\n.dashboard-card {\n  border-radius: 4px;\n  padding: 28px 34px 32px;\n}\n\n.section-label {\n  margin: 0;\n  font-size: 0.78rem;\n  color: #9ba2aa;\n  text-transform: uppercase;\n  letter-spacing: 0.08em;\n}\n\n.dashboard-card h1 {\n  margin: 10px 0 28px;\n  text-align: center;\n  font-size: clamp(2rem, 4vw, 3rem);\n  color: #737982;\n  font-weight: 500;\n}\n\n.module-grid {\n  display: grid;\n  grid-template-columns: repeat(4, minmax(0, 1fr));\n  gap: 10px;\n  max-width: 760px;\n  margin: 0 auto;\n}\n\n.module-card {\n  min-height: 122px;\n  border: 1px solid #d6dadd;\n  background: linear-gradient(180deg, #ffffff 0%, #f1f3f4 100%);\n  border-radius: 3px;\n  display: grid;\n  align-content: center;\n  justify-items: center;\n  gap: 6px;\n  color: #a1a7ae;\n}\n\n.module-card:hover {\n  background: linear-gradient(180deg, #ffffff 0%, #eceff1 100%);\n}\n\n.module-icon {\n  font-size: 2rem;\n  line-height: 1;\n}\n\n.module-card strong {\n  font-size: 1rem;\n  font-weight: 500;\n  color: #8f969f;\n}\n\n.module-card small {\n  font-size: 0.72rem;\n  color: #b2b8c0;\n}\n\n.strip-metrics {\n  display: grid;\n  grid-template-columns: repeat(4, minmax(0, 1fr));\n  gap: 12px;\n  margin-top: 14px;\n}\n\n.metric-box {\n  border-radius: 4px;\n  padding: 16px;\n}\n\n.metric-box span,\n.metric-box small {\n  display: block;\n  color: #8d949b;\n}\n\n.metric-box strong {\n  display: block;\n  margin: 8px 0 6px;\n  color: var(--ink-strong);\n  font-size: 1.45rem;\n}\n\n.content-grid {\n  display: grid;\n  grid-template-columns: 1.25fr 0.95fr;\n  gap: 14px;\n  margin-top: 14px;\n}\n\n.panel {\n  border-radius: 4px;\n  padding: 18px;\n}\n\n.large-panel {\n  grid-row: span 2;\n}\n\n.stats-panel {\n  grid-column: span 2;\n}\n\n.panel-head {\n  margin-bottom: 14px;\n}\n\n.panel-head h2 {\n  margin: 0;\n  font-size: 1.18rem;\n  font-weight: 600;\n  color: var(--ink-strong);\n}\n\n.panel-head p {\n  margin: 4px 0 0;\n  color: #9299a1;\n  font-size: 0.86rem;\n}\n\n.form-grid {\n  display: grid;\n  grid-template-columns: repeat(2, minmax(0, 1fr));\n  gap: 10px;\n}\n\n.form-grid.compact {\n  grid-template-columns: repeat(2, minmax(0, 1fr));\n}\n\n.form-grid label {\n  display: grid;\n  gap: 6px;\n  color: #747c84;\n  font-size: 0.82rem;\n  font-weight: 500;\n}\n\n.form-grid input,\n.form-grid select {\n  width: 100%;\n  border: 1px solid #cfd5da;\n  border-radius: 3px;\n  background: #ffffff;\n  color: #59606a;\n  padding: 10px 12px;\n}\n\n.checkbox-row {\n  display: flex;\n  align-items: center;\n  gap: 8px;\n  grid-column: span 2;\n}\n\n.checkbox-row input {\n  width: auto;\n}\n\n.form-grid button {\n  grid-column: span 2;\n  border: 1px solid #5e6772;\n  border-radius: 3px;\n  background: linear-gradient(180deg, #7a848f 0%, #646d78 100%);\n  color: #f2f4f7;\n  padding: 11px 14px;\n  font-weight: 600;\n}\n\n.mini-list,\n.top-products,\n.alert-list {\n  display: grid;\n  gap: 8px;\n  margin-top: 14px;\n}\n\n.mini-row,\n.top-item,\n.notice {\n  display: flex;\n  justify-content: space-between;\n  gap: 12px;\n  align-items: center;\n  border: 1px solid #d8dde1;\n  background: #ffffff;\n  border-radius: 3px;\n  padding: 12px 14px;\n}\n\n.mini-row strong,\n.top-item strong,\n.notice strong {\n  color: var(--ink-strong);\n}\n\n.mini-row p,\n.top-item p,\n.notice p {\n  margin: 3px 0 0;\n  color: #8b929a;\n  font-size: 0.79rem;\n}\n\n.mini-value {\n  text-align: right;\n}\n\n.top-item span {\n  width: 28px;\n  height: 28px;\n  border-radius: 50%;\n  display: grid;\n  place-items: center;\n  background: #d9dde2;\n  color: #636b74;\n  font-size: 0.82rem;\n  font-weight: 700;\n}\n\n.notice.warning {\n  background: var(--warning);\n}\n\n.notice.success {\n  background: var(--success);\n}\n\n.empty-state {\n  margin: 0;\n  color: #8d949b;\n}\n\n@media (max-width: 1180px) {\n  .module-grid,\n  .strip-metrics,\n  .content-grid {\n    grid-template-columns: repeat(2, minmax(0, 1fr));\n  }\n\n  .large-panel,\n  .stats-panel {\n    grid-column: span 2;\n    grid-row: auto;\n  }\n}\n\n@media (max-width: 820px) {\n  .app-shell {\n    grid-template-columns: 1fr;\n  }\n\n  .nav-rail {\n    gap: 12px;\n  }\n\n  .rail-items {\n    grid-template-columns: repeat(4, minmax(0, 1fr));\n  }\n\n  .topbar {\n    grid-template-columns: 1fr;\n  }\n\n  .topbar-right {\n    justify-content: flex-start;\n  }\n}\n\n@media (max-width: 640px) {\n  .page,\n  .topbar {\n    padding: 16px;\n  }\n\n  .dashboard-card {\n    padding: 20px 16px;\n  }\n\n  .module-grid,\n  .strip-metrics,\n  .content-grid,\n  .form-grid,\n  .form-grid.compact {\n    grid-template-columns: 1fr;\n  }\n\n  .checkbox-row,\n  .form-grid button,\n  .large-panel,\n  .stats-panel {\n    grid-column: span 1;\n  }\n\n  .mini-row,\n  .top-item,\n  .notice {\n    flex-direction: column;\n    align-items: flex-start;\n  }\n\n  .mini-value {\n    text-align: left;\n  }\n\n  .rail-items {\n    grid-template-columns: repeat(2, minmax(0, 1fr));\n  }\n}\n";
const js = "const currency = new Intl.NumberFormat('es-AR', {\n  style: 'currency',\n  currency: 'ARS',\n  maximumFractionDigits: 0,\n})\n\nconst today = new Date().toISOString().slice(0, 10)\n\nconst seedData = {\n  business: {\n    name: 'codelector local',\n    owner: 'Lucia Torres',\n    shift: 'Sucursal Centro',\n  },\n  products: [\n    { id: crypto.randomUUID(), name: 'Yerba Tradicional 1kg', sku: 'YT-100', stock: 22, price: 5400, minStock: 10, category: 'Almacen' },\n    { id: crypto.randomUUID(), name: 'Galletitas de Avena', sku: 'GA-014', stock: 14, price: 1850, minStock: 8, category: 'Kiosco' },\n    { id: crypto.randomUUID(), name: 'Lavandina 2L', sku: 'LV-210', stock: 7, price: 3200, minStock: 9, category: 'Limpieza' },\n    { id: crypto.randomUUID(), name: 'Aceite de Girasol 900ml', sku: 'AG-900', stock: 18, price: 4100, minStock: 6, category: 'Almacen' },\n  ],\n  providers: [\n    { id: crypto.randomUUID(), name: 'Distribuidora Norte', contact: 'Marina Lopez', phone: '11 4321 9988', balance: 128000, lastDelivery: '2026-07-09', category: 'Almacen' },\n    { id: crypto.randomUUID(), name: 'Higiene Sur', contact: 'Jorge Benitez', phone: '11 5511 4010', balance: 42000, lastDelivery: '2026-07-11', category: 'Limpieza' },\n  ],\n  sales: [\n    { id: crypto.randomUUID(), item: 'Yerba Tradicional 1kg', quantity: 3, amount: 16200, channel: 'Mostrador', paid: true, date: '2026-07-12' },\n    { id: crypto.randomUUID(), item: 'Aceite de Girasol 900ml', quantity: 2, amount: 8200, channel: 'WhatsApp', paid: true, date: '2026-07-12' },\n    { id: crypto.randomUUID(), item: 'Lavandina 2L', quantity: 1, amount: 3200, channel: 'Delivery', paid: false, date: '2026-07-11' },\n  ],\n  invoices: [\n    { id: crypto.randomUUID(), number: 'A-0003-000184', client: 'Punto Verde', total: 48600, status: 'Emitida', dueDate: '2026-07-20', type: 'A' },\n    { id: crypto.randomUUID(), number: 'B-0001-000992', client: 'Consumidor Final', total: 8200, status: 'Cobrada', dueDate: '2026-07-12', type: 'B' },\n  ],\n}\n\nconst modules = [\n  { id: 'lector', icon: '◯', label: 'Lector', detail: 'Escaneo rapido' },\n  { id: 'caja', icon: '⚙', label: 'Caja', detail: 'Cobros y cierres' },\n  { id: 'productos', icon: '🏷', label: 'Productos', detail: 'Catalogo y precios' },\n  { id: 'precios', icon: '$', label: 'Precios', detail: 'Margenes activos' },\n  { id: 'compras', icon: '🛒', label: 'Compras', detail: 'Ordenes y recepcion' },\n  { id: 'clientes', icon: '☀', label: 'Clientes', detail: 'Segmentos frecuentes' },\n  { id: 'proveedores', icon: '⌖', label: 'Proveedores', detail: 'Cuentas a pagar' },\n  { id: 'ventas', icon: '▣', label: 'Ventas', detail: 'Ultimos movimientos' },\n  { id: 'cheques', icon: '≡', label: 'Cheques', detail: 'Calendario financiero' },\n  { id: 'cajeros', icon: '◔', label: 'Cajeros', detail: 'Turnos y permisos' },\n  { id: 'facturacion', icon: '▤', label: 'Facturacion', detail: 'Comprobantes' },\n  { id: 'reportes', icon: '✦', label: 'Reportes', detail: 'Resumen del dia' },\n]\n\nconst storageKey = 'comercio360-data'\nconst app = document.querySelector('#app')\n\nconst loadState = () => {\n  const saved = localStorage.getItem(storageKey)\n  if (!saved) return structuredClone(seedData)\n\n  try {\n    return { ...structuredClone(seedData), ...JSON.parse(saved) }\n  } catch {\n    return structuredClone(seedData)\n  }\n}\n\nlet state = loadState()\n\nconst saveState = () => {\n  localStorage.setItem(storageKey, JSON.stringify(state))\n}\n\nconst money = (value) => currency.format(Number(value) || 0)\n\nconst getMetrics = () => {\n  const totalSales = state.sales.reduce((sum, sale) => sum + sale.amount, 0)\n  const unpaidSales = state.sales.filter((sale) => !sale.paid).reduce((sum, sale) => sum + sale.amount, 0)\n  const payables = state.providers.reduce((sum, provider) => sum + provider.balance, 0)\n  const pendingInvoices = state.invoices.filter((invoice) => invoice.status !== 'Cobrada').reduce((sum, invoice) => sum + invoice.total, 0)\n  const lowStock = state.products.filter((product) => product.stock <= product.minStock)\n\n  return { totalSales, unpaidSales, payables, pendingInvoices, lowStock }\n}\n\nconst getTopProducts = () => {\n  const sold = new Map()\n\n  for (const sale of state.sales) {\n    sold.set(sale.item, (sold.get(sale.item) || 0) + sale.quantity)\n  }\n\n  return [...sold.entries()].sort((a, b) => b[1] - a[1]).slice(0, 4)\n}\n\nconst render = () => {\n  const metrics = getMetrics()\n  const topProducts = getTopProducts()\n\n  app.innerHTML = `\n    <div class=\"app-shell\">\n      <aside class=\"nav-rail\">\n        <div class=\"brand-stack\">\n          <div class=\"brand-logo\">c</div>\n          <div class=\"rail-items\">\n            <a href=\"#dashboard\">Inicio</a>\n            <a href=\"#ventas\">Ventas</a>\n            <a href=\"#compras\">Compras</a>\n            <a href=\"#clientes\">Clientes</a>\n            <a href=\"#proveedores\">Proveedores</a>\n            <a href=\"#cajeros\">Cajeros</a>\n            <a href=\"#facturacion\">Facturas</a>\n          </div>\n        </div>\n        <div class=\"rail-foot\">Soporte</div>\n      </aside>\n\n      <div class=\"workspace\">\n        <header class=\"topbar\">\n          <div class=\"topbar-left\">\n            <strong>${state.business.name}</strong>\n            <span>${state.business.owner} - ${state.business.shift}</span>\n          </div>\n          <div class=\"searchbar\">\n            <span>⌕</span>\n            <input type=\"text\" value=\"\" placeholder=\"Buscar productos, clientes y proveedores\" />\n          </div>\n          <div class=\"topbar-right\">\n            <span class=\"status-pill\">Online</span>\n            <span class=\"avatar\">${state.business.owner[0]}</span>\n          </div>\n        </header>\n\n        <main class=\"page\">\n          <section class=\"dashboard-card\" id=\"dashboard\">\n            <p class=\"section-label\">Panel principal</p>\n            <h1>¿Que quieres hacer?</h1>\n            <div class=\"module-grid\">\n              ${modules\n                .map(\n                  (module) => `\n                    <button class=\"module-card\" data-jump=\"${module.id}\" type=\"button\">\n                      <span class=\"module-icon\">${module.icon}</span>\n                      <strong>${module.label}</strong>\n                      <small>${module.detail}</small>\n                    </button>`,\n                )\n                .join('')}\n            </div>\n          </section>\n\n          <section class=\"strip-metrics\">\n            <article class=\"metric-box\">\n              <span>Ventas del dia</span>\n              <strong>${money(metrics.totalSales)}</strong>\n              <small>${state.sales.length} operaciones</small>\n            </article>\n            <article class=\"metric-box\">\n              <span>Por cobrar</span>\n              <strong>${money(metrics.unpaidSales)}</strong>\n              <small>${state.sales.filter((sale) => !sale.paid).length} pendientes</small>\n            </article>\n            <article class=\"metric-box\">\n              <span>Stock critico</span>\n              <strong>${metrics.lowStock.length}</strong>\n              <small>${metrics.lowStock[0] ? metrics.lowStock[0].name : 'Sin alertas'}</small>\n            </article>\n            <article class=\"metric-box\">\n              <span>Facturas abiertas</span>\n              <strong>${money(metrics.pendingInvoices)}</strong>\n              <small>${state.invoices.filter((invoice) => invoice.status !== 'Cobrada').length} comprobantes</small>\n            </article>\n          </section>\n\n          <section class=\"content-grid\">\n            <article class=\"panel large-panel\" id=\"ventas\">\n              <div class=\"panel-head\">\n                <div>\n                  <h2>Ventas</h2>\n                  <p>Registra operaciones y descuenta stock automaticamente.</p>\n                </div>\n              </div>\n              <form class=\"form-grid\" data-form=\"sale\">\n                <label>\n                  Producto\n                  <select name=\"item\" required>\n                    ${state.products.map((product) => `<option value=\"${product.name}\">${product.name}</option>`).join('')}\n                  </select>\n                </label>\n                <label>\n                  Cantidad\n                  <input type=\"number\" name=\"quantity\" min=\"1\" value=\"1\" required />\n                </label>\n                <label>\n                  Monto total\n                  <input type=\"number\" name=\"amount\" min=\"1\" placeholder=\"5400\" required />\n                </label>\n                <label>\n                  Canal\n                  <select name=\"channel\">\n                    <option>Mostrador</option>\n                    <option>WhatsApp</option>\n                    <option>Delivery</option>\n                    <option>Mayorista</option>\n                  </select>\n                </label>\n                <label class=\"checkbox-row\">\n                  <input type=\"checkbox\" name=\"paid\" checked />\n                  Cobrado\n                </label>\n                <button type=\"submit\">Registrar venta</button>\n              </form>\n              <div class=\"mini-list\">\n                ${state.sales\n                  .slice()\n                  .reverse()\n                  .slice(0, 4)\n                  .map(\n                    (sale) => `\n                      <div class=\"mini-row\">\n                        <div>\n                          <strong>${sale.item}</strong>\n                          <p>${sale.date} - ${sale.channel}</p>\n                        </div>\n                        <div class=\"mini-value\">\n                          <strong>${money(sale.amount)}</strong>\n                          <p>${sale.quantity} un. - ${sale.paid ? 'Cobrado' : 'Pendiente'}</p>\n                        </div>\n                      </div>`,\n                  )\n                  .join('')}\n              </div>\n            </article>\n\n            <article class=\"panel side-panel\" id=\"productos\">\n              <div class=\"panel-head\">\n                <div>\n                  <h2>Productos</h2>\n                  <p>Alta rapida para catalogo y stock.</p>\n                </div>\n              </div>\n              <form class=\"form-grid compact\" data-form=\"product\">\n                <label>\n                  Nombre\n                  <input type=\"text\" name=\"name\" placeholder=\"Cafe molido 500g\" required />\n                </label>\n                <label>\n                  SKU\n                  <input type=\"text\" name=\"sku\" placeholder=\"CF-500\" required />\n                </label>\n                <label>\n                  Stock\n                  <input type=\"number\" name=\"stock\" min=\"0\" required />\n                </label>\n                <label>\n                  Precio\n                  <input type=\"number\" name=\"price\" min=\"0\" required />\n                </label>\n                <label>\n                  Minimo\n                  <input type=\"number\" name=\"minStock\" min=\"0\" required />\n                </label>\n                <label>\n                  Categoria\n                  <input type=\"text\" name=\"category\" placeholder=\"Almacen\" required />\n                </label>\n                <button type=\"submit\">Guardar producto</button>\n              </form>\n            </article>\n\n            <article class=\"panel\" id=\"compras\">\n              <div class=\"panel-head\">\n                <div>\n                  <h2>Compras y proveedores</h2>\n                  <p>Controla recepciones y cuentas a pagar.</p>\n                </div>\n              </div>\n              <form class=\"form-grid compact\" data-form=\"provider\">\n                <label>\n                  Empresa\n                  <input type=\"text\" name=\"name\" required />\n                </label>\n                <label>\n                  Contacto\n                  <input type=\"text\" name=\"contact\" required />\n                </label>\n                <label>\n                  Telefono\n                  <input type=\"text\" name=\"phone\" required />\n                </label>\n                <label>\n                  Saldo pendiente\n                  <input type=\"number\" name=\"balance\" min=\"0\" required />\n                </label>\n                <label>\n                  Ultima entrega\n                  <input type=\"date\" name=\"lastDelivery\" value=\"${today}\" required />\n                </label>\n                <label>\n                  Categoria\n                  <input type=\"text\" name=\"category\" required />\n                </label>\n                <button type=\"submit\">Guardar proveedor</button>\n              </form>\n              <div class=\"mini-list\">\n                ${state.providers\n                  .slice(0, 4)\n                  .map(\n                    (provider) => `\n                      <div class=\"mini-row\">\n                        <div>\n                          <strong>${provider.name}</strong>\n                          <p>${provider.contact} - ${provider.phone}</p>\n                        </div>\n                        <div class=\"mini-value\">\n                          <strong>${money(provider.balance)}</strong>\n                          <p>${provider.category}</p>\n                        </div>\n                      </div>`,\n                  )\n                  .join('')}\n              </div>\n            </article>\n\n            <article class=\"panel\" id=\"facturacion\">\n              <div class=\"panel-head\">\n                <div>\n                  <h2>Facturacion</h2>\n                  <p>Emite comprobantes y sigue el estado de cobro.</p>\n                </div>\n              </div>\n              <form class=\"form-grid compact\" data-form=\"invoice\">\n                <label>\n                  Numero\n                  <input type=\"text\" name=\"number\" placeholder=\"B-0001-001245\" required />\n                </label>\n                <label>\n                  Cliente\n                  <input type=\"text\" name=\"client\" required />\n                </label>\n                <label>\n                  Total\n                  <input type=\"number\" name=\"total\" min=\"1\" required />\n                </label>\n                <label>\n                  Tipo\n                  <select name=\"type\">\n                    <option>A</option>\n                    <option>B</option>\n                    <option>C</option>\n                  </select>\n                </label>\n                <label>\n                  Vencimiento\n                  <input type=\"date\" name=\"dueDate\" value=\"${today}\" required />\n                </label>\n                <label>\n                  Estado\n                  <select name=\"status\">\n                    <option>Emitida</option>\n                    <option>En revision</option>\n                    <option>Cobrada</option>\n                  </select>\n                </label>\n                <button type=\"submit\">Guardar factura</button>\n              </form>\n              <div class=\"mini-list\">\n                ${state.invoices\n                  .slice()\n                  .reverse()\n                  .slice(0, 4)\n                  .map(\n                    (invoice) => `\n                      <div class=\"mini-row\">\n                        <div>\n                          <strong>${invoice.number}</strong>\n                          <p>${invoice.client} - Tipo ${invoice.type}</p>\n                        </div>\n                        <div class=\"mini-value\">\n                          <strong>${money(invoice.total)}</strong>\n                          <p>${invoice.status}</p>\n                        </div>\n                      </div>`,\n                  )\n                  .join('')}\n              </div>\n            </article>\n\n            <article class=\"panel stats-panel\" id=\"clientes\">\n              <div class=\"panel-head\">\n                <div>\n                  <h2>Resumen rapido</h2>\n                  <p>Accesos directos para caja, clientes y alertas.</p>\n                </div>\n              </div>\n              <div class=\"top-products\">\n                ${topProducts.length\n                  ? topProducts\n                      .map(\n                        ([item, quantity], index) => `\n                          <div class=\"top-item\">\n                            <span>${index + 1}</span>\n                            <div>\n                              <strong>${item}</strong>\n                              <p>${quantity} unidades vendidas</p>\n                            </div>\n                          </div>`,\n                      )\n                      .join('')\n                  : '<p class=\"empty-state\">Todavia no hay ventas cargadas.</p>'}\n              </div>\n              <div class=\"alert-list\">\n                ${\n                  metrics.lowStock.length\n                    ? metrics.lowStock\n                        .map(\n                          (product) => `\n                            <div class=\"notice warning\">\n                              <strong>${product.name}</strong>\n                              <p>Stock ${product.stock} / minimo ${product.minStock}</p>\n                            </div>`,\n                        )\n                        .join('')\n                    : '<div class=\"notice success\"><strong>Inventario estable</strong><p>No hay productos debajo del minimo.</p></div>'\n                }\n              </div>\n            </article>\n          </section>\n        </main>\n      </div>\n    </div>\n  `\n\n  bindEvents()\n}\n\nconst bindEvents = () => {\n  for (const form of document.querySelectorAll('form[data-form]')) {\n    form.addEventListener('submit', handleSubmit)\n  }\n\n  for (const button of document.querySelectorAll('[data-jump]')) {\n    button.addEventListener('click', () => {\n      const target = document.getElementById(button.dataset.jump)\n      if (target) target.scrollIntoView({ behavior: 'smooth', block: 'start' })\n    })\n  }\n}\n\nconst handleSubmit = (event) => {\n  event.preventDefault()\n\n  const form = event.currentTarget\n  const formData = new FormData(form)\n  const kind = form.dataset.form\n\n  if (kind === 'sale') {\n    const item = formData.get('item')\n    const quantity = Number(formData.get('quantity'))\n    const amount = Number(formData.get('amount'))\n    const paid = formData.get('paid') === 'on'\n    const product = state.products.find((entry) => entry.name === item)\n\n    if (product) product.stock = Math.max(0, product.stock - quantity)\n\n    state.sales.push({\n      id: crypto.randomUUID(),\n      item,\n      quantity,\n      amount,\n      channel: formData.get('channel'),\n      paid,\n      date: today,\n    })\n  }\n\n  if (kind === 'product') {\n    state.products.push({\n      id: crypto.randomUUID(),\n      name: formData.get('name'),\n      sku: formData.get('sku'),\n      stock: Number(formData.get('stock')),\n      price: Number(formData.get('price')),\n      minStock: Number(formData.get('minStock')),\n      category: formData.get('category'),\n    })\n  }\n\n  if (kind === 'provider') {\n    state.providers.unshift({\n      id: crypto.randomUUID(),\n      name: formData.get('name'),\n      contact: formData.get('contact'),\n      phone: formData.get('phone'),\n      balance: Number(formData.get('balance')),\n      lastDelivery: formData.get('lastDelivery'),\n      category: formData.get('category'),\n    })\n  }\n\n  if (kind === 'invoice') {\n    state.invoices.push({\n      id: crypto.randomUUID(),\n      number: formData.get('number'),\n      client: formData.get('client'),\n      total: Number(formData.get('total')),\n      type: formData.get('type'),\n      dueDate: formData.get('dueDate'),\n      status: formData.get('status'),\n    })\n  }\n\n  saveState()\n  form.reset()\n  render()\n}\n\nrender()\n";
